mapper.select:
SELECT COUNT( LEAGUE_IDX ) AS CNT FROM LEAGUE
AND LEAGUE_NAME = #{ league_name }
AND ${searchType} Like '%' || #{ keyword } || '%'

mapper.update:
     UPDATE SBN.TEAM_LEAGUE
	  SET    JOIN_STATUS = 1
	  WHERE  LEAGUE_IDX = #{league_idx}
	   AND  TEAM_IDX = #{team_idx}

mapper.delete:
     DELETE FROM SBN.TEAM_LEAGUE
	  WHERE  LEAGUE_IDX = #{league_idx}
	   AND  TEAM_IDX = #{team_idx}

mapper.update:
     UPDATE LEAGUE
	  SET    LEAGUE_NAME     = #{league_name},
	         LEAGUE_LOCATION = #{league_location},
	         LEAGUE_CONTENT  = #{league_content}
	  WHERE  LEAGUE_IDX      = #{league_idx}

mapper.select:
     SELECT  COUNT(*)
	  FROM   SBN.TEAM_LEAGUE
	  WHERE  LEAGUE_IDX = #{league_idx}
	    AND  TEAM_IDX = #{team_idx}
